const raw = $input.first().json;
const body = raw.body || raw;

if (body.payload?.fromMe === true) return [];
if (body.event && body.event !== 'message') return [];

const from  = body.payload?.from || '';
const phone = from.replace(/@.*$/, '');
const text  = (body.payload?.body || '').trim();

if (!from || !text) return [];

return [{ json: {
  phone,
  chatId:  from,
  text,
  session: body.session || 'default',
  raw:     body.payload
} }];

const parsed = $('Parsear mensagem').item.json;

let convAll = [], patAll = [], slotAll = [];
try { convAll = $('Buscar conversa').all(); } catch(e) {}
try { patAll  = $('Buscar paciente').all(); } catch(e) {}
try { slotAll = $('Buscar slots').all();    } catch(e) {}

const conv    = convAll[0]?.json || { state: 'idle', context: '{}', clinic_id: null };
const patient = patAll[0]?.json  || null;
const slots   = slotAll.map(s => s.json);

return [{ json: {
  phone:    parsed.phone,
  chatId:   parsed.chatId,
  text:     parsed.text,
  session:  parsed.session,
  conv, patient, slots,
  clinicId: slots[0]?.clinic_id || conv.clinic_id || 'aaaaaaaa-0000-0000-0000-000000000001'
} }];

const data = $input.first().json;
const { text, phone, chatId, session, conv, patient, slots, clinicId } = data;

const state = conv?.state || 'idle';
let ctx = {};
try { ctx = typeof conv?.context === 'string' ? JSON.parse(conv.context) : (conv?.context || {}); } catch(e) {}

const input = text.trim().toLowerCase();
const num   = parseInt(text.trim());

const dias = ['Dom','Seg','Ter','Qua','Qui','Sex','Sáb'];
const top5 = (slots || []).slice(0, 5);
const slotsList = top5.length
  ? top5.map((s, i) => {
      const d = new Date(s.date + 'T00:00:00-03:00');
      return `${i+1}. ${dias[d.getDay()]} ${d.toLocaleDateString('pt-BR',{day:'2-digit',month:'2-digit'})} as ${s.time.slice(0,5)}`;
    }).join('\n')
  : null;

const SERVICES = ['Consulta clinica', 'Retorno', 'Exame laboratorial'];

const MENU_MSG =
  'Ola! Sou a assistente virtual da Clinica Piloto.\n\n' +
  'Como posso ajudar?\n\n' +
  '1. Agendar consulta\n' +
  '2. Cancelar consulta\n' +
  '3. Falar com a recepcao\n\n' +
  'Digite o numero da opcao.';

const SERVICES_MSG =
  'Qual servico voce precisa?\n\n' +
  '1. Consulta clinica\n' +
  '2. Retorno\n' +
  '3. Exame laboratorial\n\n' +
  'Digite o numero.';

let message    = '';
let newState   = 'menu';
let newContext = {};
let action     = 'reply';
let bookingData = null;

switch (state) {

  case 'menu':
    if (num === 1) {
      if (!slotsList) {
        message  = 'Nao ha horarios disponiveis no momento.\nTente amanha ou ligue para a recepcao.';
        newState = 'idle';
      } else {
        message  = SERVICES_MSG;
        newState = 'selecting_service';
      }
    } else if (num === 2) {
      message  = 'Para cancelar sua consulta, entre em contato com nossa recepcao.\nEm breve voce podera cancelar por aqui mesmo!';
      newState = 'idle';
    } else if (num === 3) {
      message  = 'Certo! Nossa recepcionista vai entrar em contato em breve.';
      newState = 'idle';
    } else {
      message  = 'Nao entendi. Por favor, escolha uma opcao:\n\n' + MENU_MSG;
      newState = 'menu';
    }
    break;

  case 'selecting_service':
    if (num >= 1 && num <= 3) {
      const svc = SERVICES[num - 1];
      if (!slotsList) {
        message  = 'Sem horarios disponiveis agora.\nTente amanha ou ligue para a recepcao.';
        newState = 'idle';
      } else {
        message  = `Otimo! Horarios disponiveis para ${svc}:\n\n${slotsList}\n\nDigite o numero do horario desejado.`;
        newState = 'selecting_slot';
        newContext = { service: svc };
      }
    } else {
      message  = 'Escolha uma opcao valida (1, 2 ou 3):\n\n' + SERVICES_MSG;
      newState = 'selecting_service';
      newContext = ctx;
    }
    break;

  case 'selecting_slot':
    const svc = ctx.service || 'Consulta clinica';
    if (num >= 1 && num <= top5.length) {
      const slot    = top5[num - 1];
      const d       = new Date(slot.date + 'T00:00:00-03:00');
      const dateStr = `${dias[d.getDay()]} ${d.toLocaleDateString('pt-BR',{day:'2-digit',month:'2-digit'})} as ${slot.time.slice(0,5)}`;
      const patientId = patient?.id || 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
        const r = Math.random() * 16 | 0;
        return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
      });
      message  = `Agendamento confirmado!\n\nServico: ${svc}\nData: ${dateStr}\n\nAte la! Voce recebera um lembrete no dia anterior.`;
      newState = 'idle';
      action   = 'book';
      bookingData = {
        slot, slotId: slot.id, service: svc,
        patientId, patientName: patient?.name || 'Paciente',
        clinicId: slot.clinic_id || clinicId
      };
    } else {
      message  = `Escolha um numero entre 1 e ${top5.length}:\n\n${slotsList}`;
      newState = 'selecting_slot';
      newContext = ctx;
    }
    break;

  case 'confirming':
    const isYes = num === 1 || ['sim','s','ok','confirmo','vou'].some(w => input.includes(w));
    if (isYes) {
      message = 'Presenca confirmada! Ate amanha.\n\nLembre-se: chegue 15 minutos antes.';
    } else {
      message = 'Tudo bem! Sua consulta foi cancelada. Quando quiser reagendar, e so chamar.';
    }
    newState = 'idle';
    break;

  case 'idle':
  default:
    message  = MENU_MSG;
    newState = 'menu';
    break;
}

const convId = conv?.id || 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
  const r = Math.random() * 16 | 0;
  return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
});

return [{ json: {
  message, newState, newContext, action, bookingData,
  phone, chatId, session, clinicId, convId,
  conv, patient, slots
} }];

const proc   = $('Processar estado').item.json;
const apptId = $('Criar Appointment').item.json?.id || null;
return [{ json: {
  message:    proc.message,
  newState:   proc.newState,
  newContext: apptId ? { appointment_id: apptId } : {},
  phone:      proc.phone,
  chatId:     proc.chatId,
  session:    proc.session,
  clinicId:   proc.clinicId,
  convId:     proc.convId
} }];

const proc = $('Processar estado').item.json;
return [{ json: {
  message:    proc.message,
  newState:   proc.newState,
  newContext: proc.newContext,
  phone:      proc.phone,
  chatId:     proc.chatId,
  session:    proc.session,
  clinicId:   proc.clinicId,
  convId:     proc.convId
} }];
